  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">JCB x Circle Stablecoin-MOU -- Kartennetzwerk-Abwicklung vs. Stablecoin-Abwicklung</text>
  <g font-family="sans-serif">
    <text x="20" y="60" fill="#a1a1aa" font-size="13">1. Zwei Arbeitsstränge des MOU</text>
    <rect x="20" y="73" width="320" height="56" rx="8" fill="#14b8a6" opacity="0.9"/>
    <text x="180" y="98" fill="#111113" font-size="13" font-weight="700" text-anchor="middle">1. Grenzüberschreitende Transfers</text>
    <text x="180" y="118" fill="#111113" font-size="12" text-anchor="middle">Beginnt mit JCBs internem PoC</text>
    <rect x="360" y="73" width="320" height="56" rx="8" fill="#38bdf8" opacity="0.9"/>
