    <rect x="20" y="219" width="660" height="40" rx="8" fill="#f87171" opacity="0.9"/>
    <text x="350" y="244" fill="#111113" font-size="13" font-weight="700" text-anchor="middle">Stablecoin (USDC) On-Chain-Transfer: theoretisch Abwicklung in Minuten</text>

    <text x="20" y="290" fill="#a1a1aa" font-size="13">3. JCBs Größenordnung (laut eigenen Angaben)</text>
    <rect x="20" y="303" width="660" height="76" rx="8" fill="#3f3f46"/>
